parameters.jsCode:
// n8n: CODE - Build assessment result mail (PASS/FAIL — thread reply)
// Place AFTER: IF - Assessment finished? (true branch)
// Place BEFORE: MAIL - Reply candidate (assessment result)
//
// Gmail node settings:
//   Resource:   thread
//   Operation:  reply
//   Thread ID:  {{ $json.gmail_thread_id }}
//   Message ID: {{ $json.gmail_message_id }}
//   Email Type: HTML
//   Message:    {{ $json.mail_body_html }}

function pickNodeJson(...names) {
  for (const name of names) {
    if (!name) continue;
    try {
      const raw = $(name).first().json;
      if (raw && typeof raw === 'object') return raw;
    } catch (_) {}
  }
  return null;
}

function pickSessionRow() {
  const built =
    pickNodeJson(
      'CODE - Build Speech LLM context',
      'CODE - Build Speech LLM context1',
      'CODE - Build LLM context',
      'CODE - Build LLM context1'
    ) || {};
  if (built.session?.id) return built.session;

  const fetchRaw = pickNodeJson(
    'HTTP - Fetch Session',
    'HTTP - Fetch Session1',
    'HTTP - SB PATCH session interview_history',
    'HTTP - SB PATCH session interview_history1'
  );
  const row = Array.isArray(fetchRaw) ? fetchRaw[0] : fetchRaw;
  if (row?.id) return row;

  return {};
}

const parse =
  pickNodeJson(
    'CODE - Pick Parse Result',
    'CODE - Pick Parse Result1',
    'CODE - Parse Speech Result',
    'CODE - Parse Speech Result1',
    'CODE - Parse Technical Result',
    'CODE - Parse Technical Result1'
  ) || $input.first().json || {};

const session = pickSessionRow();
const cfg = parse.config || session.config || {};

const threadId = String(
  parse.gmail_thread_id || session.gmail_thread_id || ''
).trim();
const msgId = String(
  parse.gmail_message_id || session.gmail_message_id || ''
).trim();

if (!threadId || threadId.startsWith('draft-')) {
  const sid = parse.session_id || session.id || 'unknown';
  throw new Error(
    'gmail_thread_id missing on session ' +
      sid +
      ' — CV screening shortlist mail must PATCH gmail_thread_id to assessment_sessions. ' +
      'Check Supabase row, run supabase_gmail_thread_columns.sql, and verify CV Screening workflow: ' +
      'MAIL - Email outreach agent (shortlist) → HTTP - SB PATCH session gmail thread.'
  );
}
if (!msgId) {
  throw new Error(
    'gmail_message_id missing on session — re-run shortlist flow or set from first mail.'
  );
}

const result = String(parse.result || 'FAIL').toUpperCase();
const passed = result === 'PASS';
const score = parse.score ?? parse.average_score ?? '—';
const role = String(cfg.requisition_title || 'the role');
const org = String(cfg.organization_name || 'Talent Acquisition Team');
const feedback = String(parse.feedback || '').trim();
const sessionId = String(parse.session_id || session.id || '');

// PASS: do not email the candidate here — interviewer pitch runs first; candidate gets
// slot options only after POST /webhook/talent/scheduling-slots (Build candidate slot mail).
if (passed) {
  return [
    {
      json: {
        ...parse,
        session_id: sessionId,
        skip_candidate_result_mail: true,
        mail_stage: 'pass_deferred_to_scheduling',
        result,
        candidate_email: parse.candidate_email || session.candidate_email,
        config: cfg,
      },
    },
  ];
}

const sectionTitle = 'Assessment Result';
const headline = `Thank you for completing the assessment for <strong>${role.replace(/</g, '&lt;')}</strong>.`;

const nextStep =
  '<p>Unfortunately you did not meet the pass threshold for this role at this time.</p>';

const mailBodyHtml = `<!DOCTYPE html>
<html><head><meta charset="UTF-8"></head>
<body style="margin:0;padding:0;background:#f1f5f9;font-family:Segoe UI,Arial,sans-serif;">
  <table width="100%" cellpadding="0" cellspacing="0" style="background:#f1f5f9;padding:24px 16px;">
    <tr><td align="center">
      <table width="100%" style="max-width:560px;background:#fff;border-radius:12px;padding:28px;">
        <tr><td style="color:#334155;font-size:15px;line-height:1.6;">
          <p style="margin:0 0 8px;font-size:12px;letter-spacing:.08em;text-transform:uppercase;color:#64748b;">── ${sectionTitle} ──</p>
          <p>Hi,</p>
          <p>${headline}</p>
          <p><strong>Overall score:</strong> ${score}/100 &nbsp;|&nbsp; <strong>Result:</strong> ${result}</p>
          ${feedback ? `<p style="color:#475569;font-size:14px;">${feedback.replace(/</g, '&lt;')}</p>` : ''}
          ${nextStep}
          <p>Best regards,<br>${org.replace(/</g, '&lt;')}</p>
        </td></tr>
      </table>
    </td></tr>
  </table>
</body></html>`;

return [
  {
    json: {
      ...parse,
      session_id: sessionId,
      gmail_thread_id: threadId,
      gmail_message_id: msgId,
      mail_subject: session.mail_subject || parse.mail_subject || '',
      mail_body_html: mailBodyHtml,
      mail_stage: 'fail',
      candidate_email: parse.candidate_email || session.candidate_email,
      config: cfg,
    },
  },
];

// n8n: CODE - Merge Gmail reply response
// Paste AFTER any Gmail "Thread → Reply" node.
// Prepares Supabase PATCH so the next reply chains to this message.
//
// Wire:
//   Gmail Thread Reply → this node → HTTP PATCH session gmail message
//
// Set HTTP PATCH node:
//   URL:  {{ $json._gmail_patch_url }}
//   Body: {{ $json._gmail_patch_body }}

function pickSessionContext() {
  const names = [
    'CODE - Build candidate slot mail',
    'CODE - Build assessment result mail',
    'CODE - Build interview confirmed mail',
    'CODE - Build Gmail thread reply context',
    'CODE - Prep scheduling from PASS',
    'CODE - Parse Result',
    'HTTP - SB GET session (slots)',
    'HTTP - SB GET session (confirmed)',
    'HTTP - Fetch Session',
    'HTTP - Fetch Session1',
  ];
  let merged = {};
  for (const name of names) {
    try {
      merged = { ...merged, ...($input.first().json || {}), ...$(name).first().json };
    } catch (_) {}
  }
  return merged;
}

function resolveGmailPayload(input, ...mailNodeNames) {
  if (input && (input.id || input.messageId || input.threadId || input.thread_id)) {
    return input;
  }
  for (const name of mailNodeNames) {
    if (!name) continue;
    try {
      const raw = $(name).first().json;
      if (raw && (raw.id || raw.messageId || raw.threadId || raw.thread_id)) return raw;
    } catch (_) {}
  }
  return input || {};
}

const gmail = resolveGmailPayload(
  $input.first().json,
  'MAIL - Candidate slot options',
  'MAIL - Candidate slot options1',
  'MAIL - Candidate pitch mail',
  'MAIL - Candidate pitch mail1',
  'MAIL - Notify candidate',
  'MAIL - Notify candidate1',
  'MAIL - Reply candidate (assessment result)',
  'MAIL - Reply candidate (assessment result)1'
);
const ctx = pickSessionContext();
const cfg = ctx.config || {};

const msgId = String(gmail.id || gmail.messageId || '').trim();
const threadId = String(gmail.threadId || gmail.thread_id || ctx.gmail_thread_id || '').trim();

const sessionId = String(
  ctx.session_id || ctx.session_db_id || ctx.id || ''
).trim();

const patchReady = Boolean(sessionId && threadId && msgId);
if (!patchReady) {
  return [
    {
      json: {
        ...ctx,
        _gmail_patch_skipped: true,
        _gmail_patch_skip_reason: [
          !sessionId ? 'missing session_id' : null,
          !threadId ? 'missing gmail_thread_id' : null,
          !msgId ? 'missing gmail message id' : null,
        ]
          .filter(Boolean)
          .join('; '),
        _gmail_patch_url: '',
        _gmail_patch_body: {},
      },
    },
  ];
}

const b = String(cfg.supabase_url || '').replace(/\/+$/, '');
const tb = cfg.table_assessment_sessions || 'assessment_sessions';

return [
  {
    json: {
      ...ctx,
      gmail_message_id: msgId,
      gmail_thread_id: threadId,
      _gmail_patch_url: `${b}/rest/v1/${tb}?id=eq.${encodeURIComponent(sessionId)}`,
      _gmail_patch_body: {
        gmail_message_id: msgId,
        gmail_thread_id: threadId,
        updated_at: new Date().toISOString(),
      },
    },
  },
];

// n8n: CODE - Prep scheduling from PASS
// After assessment result mail PATCH — loads session row for scheduling chain

function pickNodeJson(...names) {
  for (const name of names) {
    if (!name) continue;
    try {
      const raw = $(name).first().json;
      if (raw && typeof raw === 'object') return raw;
    } catch (_) {}
  }
  return null;
}

function pickSessionRow() {
  const built =
    pickNodeJson(
      'CODE - Build Speech LLM context',
      'CODE - Build Speech LLM context1',
      'CODE - Build LLM context',
      'CODE - Build LLM context1'
    ) || {};
  if (built.session?.id) return built.session;

  const fetchRaw = pickNodeJson('HTTP - Fetch Session', 'HTTP - Fetch Session1');
  const row = Array.isArray(fetchRaw) ? fetchRaw[0] : fetchRaw;
  if (row?.id) return row;

  return {};
}

const parse =
  pickNodeJson(
    'CODE - Pick Parse Result',
    'CODE - Pick Parse Result1',
    'CODE - Parse Speech Result',
    'CODE - Parse Speech Result1',
    'CODE - Parse Technical Result',
    'CODE - Parse Technical Result1'
  ) || $input.first().json || {};
const session = pickSessionRow();
const cfg = { ...(session.config || {}), ...(parse.config || {}) };

return [
  {
    json: {
      ...parse,
      ...session,
      session_id: session.id || parse.session_id,
      candidate_email: parse.candidate_email || session.candidate_email,
      score: parse.score ?? session.score,
      result: parse.result || session.result,
      requisition_title: cfg.requisition_title || session.requisition_title,
      config: cfg,
      gmail_thread_id: session.gmail_thread_id,
      gmail_message_id: session.gmail_message_id,
      mail_subject: session.mail_subject,
      interviewer_gmail_thread_id: session.interviewer_gmail_thread_id,
      interviewer_gmail_message_id: session.interviewer_gmail_message_id,
    },
  },
];

// n8n: CODE - Build interviewer mail context
// Place BEFORE: MAIL - Interviewer pitch mail
// Frontend scheduling: email link uses ?session=UUID (no n8n WAIT / resumeUrl)
//
// MAIL node settings:
//   To:      {{ $json.interviewer_email }}
//   Subject: {{ $json.mail_subject }}
//   Message: {{ $json.mail_body_html }}  (HTML — no expression injection needed)

function extractConfig(row) {
  const out = {};
  if (!row || typeof row !== 'object') return out;
  if (row.config && typeof row.config === 'object') Object.assign(out, row.config);
  for (const [k, v] of Object.entries(row)) {
    if (k.startsWith('config.') && v != null && String(v).trim()) {
      out[k.slice(7)] = String(v).trim();
    }
  }
  return out;
}

function pickNodeJson(...names) {
  for (const name of names) {
    if (!name) continue;
    try {
      const raw = $(name).first().json;
      if (raw && typeof raw === 'object') return raw;
    } catch (_) {}
  }
  return null;
}

function mergeConfig(...sources) {
  const out = {};
  for (const src of sources) {
    if (!src || typeof src !== 'object') continue;
    Object.assign(out, extractConfig(src));
    if (src.config && typeof src.config === 'object') {
      for (const [k, v] of Object.entries(src.config)) {
        if (v != null && String(v).trim()) out[k] = String(v).trim();
      }
    }
    for (const [k, v] of Object.entries(src)) {
      if (k.startsWith('config.') && v != null && String(v).trim()) {
        out[k.slice(7)] = String(v).trim();
      }
    }
  }
  return out;
}

function loadWorkflowConfig() {
  const names = [
    'CFG - Workflow configuration',
    'CFG - Workflow configuration1',
    'CFG - Workflow',
    'CFG - Assessment Config',
    'CFG - Assessment Config1',
    'CFG - Reply track (merge)',
    'CODE - Normalize Data',
    'CODE - Normalize Data1',
    'CODE - Prep scheduling from PASS',
    'CODE - Prep scheduling from PASS1',
    'CODE - Parse Result',
    'CODE - Parse Result1',
  ];
  const rows = names.map((n) => pickNodeJson(n)).filter(Boolean);
  return mergeConfig(...rows);
}

function pickAssessmentContext() {
  const input = $input.first().json || {};
  const names = [
    'CODE - Prep scheduling from PASS',
    'CODE - Prep scheduling from PASS1',
    'CODE - Parse Result',
    'CODE - Parse Result1',
    'CODE - Normalize Data',
    'CODE - Normalize Data1',
    'HTTP - SB PATCH session interview_history',
    'HTTP - SB PATCH session interview_history1',
